      17:{q:"Tehlikeli ATIK özel olarak neyi gerektirir?",options:["Özel boya rengi","Tehlikeli atık manifestosu","Yüksek sesli kabin radyosu","Parlak uyarı bayrağı"],explanation:"Tehlikeli atık, tehlikeli atık manifestosu gerektirir."},
      18:{q:"Sınıf 1 patlayıcı yakınında kullanılan aletler nasıl olmalı?",options:["Kıvılcım çıkaran çelik","Kıvılcımsız aletler","Çok ağır çubuklar","Kırmızı boyalı olanlar"],explanation:"Patlayıcı yakınında kıvılcımsız alet kullan."},
      19:{q:"Plakartların yerinde olduğunu ne zaman kontrol etmelisin?",options:["Sefer boyunca asla","Seferden önce ve sırasında","Sadece teslimde","Sadece hava kararınca"],explanation:"Plakartların seferden önce ve sırasında yerinde olduğundan emin ol."},
      20:{q:"Göndericinin acil bilgisi neye yarar?",options:["Ürünü satmaya yardıma","Ekibin sızıntıyla baş etmesine","Radyo kanalı seçmeye","Doğru lastiği seçmeye"],explanation:"Acil müdahale ekiplerinin sızıntı/yangınla baş etmesine yardım eder."},
      21:{q:"Radyoaktif (Sınıf 7) sevkiyatları kısmen neyle kontrol edilir?",options:["Bir müzik çalma indeksiyle","Maruziyeti sınırlayan taşıma indeksiyle","Sadece basit bir renk koduyla","Bir yol hız indeksiyle"],explanation:"Taşıma indeksi araçtaki toplam radyasyon maruziyetini sınırlar."},
      22:{q:"Yolda hazmat'ı araçlar arası aktarmak nasıldır?",options:["Şiddetle teşvik edilir","Acil durum dışında kaçınılır","Saatte bir gerekir","Hareket halinde yapılır"],explanation:"Acil durum dışında araçlar arası hazmat aktarımından kaçın."},
      23:{q:"Deniz kirleticileri (marine pollutant) nasıl olmalı?",options:["Tamamen gizli tutulmalı","Gerektiği gibi işaretlenmeli","Önce dökülmeli","İşaretsiz bırakılmalı"],explanation:"Deniz kirleticileri gerekli işaretleri taşımalı."}
